// Get visit from webhook
const body = typeof $json.body === 'string' ? JSON.parse($json.body) : ($json.body || {});
const visitsToAdd = body.visit ? [body.visit] : (body.visits || []);
if (!visitsToAdd.length) throw new Error('No visit data');

// Your GitHub token (paste below)
// Create at: https://github.com/settings/tokens (needs repo scope)
const GITHUB_TOKEN = '__YOUR_GITHUB_TOKEN__';

const headers = {
  'Authorization': 'Bearer ' + GITHUB_TOKEN,
  'Accept': 'application/vnd.github.v3+json',
  'User-Agent': 'n8n-analytics'
};

const url = 'https://api.github.com/repos/thekingsmakers/desertlink.it.com/contents/data/visits.json';

// 1. Fetch current file
const getRes = await $http.get(url, { headers });
const sha = getRes.data.sha;

let visits = [];
try {
  const decoded = Buffer.from(getRes.data.content, 'base64').toString('utf-8');
  visits = JSON.parse(decoded);
  if (!Array.isArray(visits)) visits = [];
} catch(e) {}

// 2. Merge new visits (dedup by id)
const existingIds = new Set(visits.map(v => v && v.id));
visitsToAdd.forEach(v => {
  if (v && v.id && !existingIds.has(v.id)) {
    visits.push(v);
    existingIds.add(v.id);
  }
});

// 3. Push updated file
const raw = JSON.stringify(visits, null, 2);
await $http.put(url, {
  message: 'analytics: record visit',
  content: Buffer.from(raw).toString('base64'),
  sha: sha
}, { headers });

return [{ json: { success: true, total: visits.length, added: visitsToAdd.length } }];
